// src/pages/DashboardHome.js
import React, { useEffect, useState } from 'react';
import Charts from '../components/Charts';
import StatCard from '../components/StatCard';
import api from '../services/api';
import WebSocketService from '../services/WebSocketService';
import { MapContainer, TileLayer, Marker, Popup } from 'react-leaflet';
import L from 'leaflet';
import 'leaflet/dist/leaflet.css';

// Fix Leaflet default marker
import markerIcon2x from 'leaflet/dist/images/marker-icon-2x.png';
import markerIcon from 'leaflet/dist/images/marker-icon.png';
import markerShadow from 'leaflet/dist/images/marker-shadow.png';

delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconUrl: markerIcon,
  iconRetinaUrl: markerIcon2x,
  shadowUrl: markerShadow,
});

const DashboardHome = () => {
  const [vehicleStats, setVehicleStats] = useState({
    total: 5,
    active: 2,
    idle: 1,
    maintenance: 2,
  });
  const [vehicles, setVehicles] = useState([]);
  const [loading, setLoading] = useState(true);

  // Fetch initial vehicle data
  useEffect(() => {
    const fetchData = async () => {
      try {
        const response = await api.get('/vehicles');
        const data = response.data;
        setVehicles(data);
        setVehicleStats({
          total: data.length,
          active: data.filter(v => v.status === 'ACTIVE').length,
          idle: data.filter(v => v.status === 'IDLE').length,
          maintenance: data.filter(v => v.status === 'MAINTENANCE').length,
        });
      } catch (err) {
        console.error('Error fetching vehicle data:', err);
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, []);

  // WebSocket for live updates
  useEffect(() => {
    WebSocketService.connect();
    WebSocketService.subscribe('/topic/vehicles', (message) => {
      const vehicleData = JSON.parse(message.body);

      // Update vehicles state
      setVehicles(prev => {
        const filtered = prev.filter(v => v.id !== vehicleData.id);
        return [...filtered, vehicleData];
      });

      // Update stats
      setVehicleStats(prevStats => {
        const updatedVehicles = [...vehicles.filter(v => v.id !== vehicleData.id), vehicleData];
        return {
          total: updatedVehicles.length,
          active: updatedVehicles.filter(v => v.status === 'ACTIVE').length,
          idle: updatedVehicles.filter(v => v.status === 'IDLE').length,
          maintenance: updatedVehicles.filter(v => v.status === 'MAINTENANCE').length,
        };
      });
    });

    return () => WebSocketService.disconnect();
  }, [vehicles]);

  const center = vehicles.length
    ? [vehicles[0].lat, vehicles[0].lng]
    : [20.5937, 78.9629]; // default India center

  return (
    <div className="space-y-6">
      <h2 className="g-title">Dashboard Home</h2>

      {/* Stat Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard title="Total Vehicles" value={vehicleStats.total} color="blue" loading={loading} />
        <StatCard title="Active Vehicles" value={vehicleStats.active} color="green" loading={loading} />
        <StatCard title="Idle Vehicles" value={vehicleStats.idle} color="yellow" loading={loading} />
        <StatCard title="Maintenance" value={vehicleStats.maintenance} color="red" loading={loading} />
      </div>

      {/* Charts */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="stat-card">
          <h3 className="text-lg font-semibold mb-4">Vehicle Status Chart</h3>
          <Charts
            type="doughnut"
            data={{
              labels: ['Active', 'Idle', 'Maintenance'],
              datasets: [
                {
                  data: [vehicleStats.active, vehicleStats.idle, vehicleStats.maintenance],
                  backgroundColor: ['#22c55e', '#facc15', '#ef4444'],
                },
              ],
            }}
          />
        </div>

        <div className="stat-card">
          <h3 className="text-lg font-semibold mb-4">Live Vehicle Map</h3>
          {loading ? (
            <p className="text-gray-600">Loading map...</p>
          ) : (
            <MapContainer center={center} zoom={5} className="w-full h-[400px] rounded-lg shadow-md">
              <TileLayer
                attribution='&copy; <a href="https://www.openstreetmap.org/">OpenStreetMap</a> contributors'
                url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
              />
              {vehicles.map(vehicle => (
                <Marker key={vehicle.id} position={[vehicle.lat, vehicle.lng]}>
                  <Popup>
                    🚗 Vehicle {vehicle.id} <br /> Status: {vehicle.status}
                  </Popup>
                </Marker>
              ))}
            </MapContainer>
          )}
        </div>
      </div>
    </div>
  );
};

export default DashboardHome;
